-- Adds a "kind" column to platform_cache (existing exchange rows default to
-- 'exchange', which is what they already are) and seeds real logos for the curated
-- wallet/DeFi catalog (shared/src/platforms/seed.json) -- previously initials-only,
-- since no CoinGecko-equivalent API exists for wallet apps or most DeFi protocols.
--
-- Sourced once, verified, and embedded as data: URIs -- never fetched live at
-- request time. Wallets (metamask, phantom, rabby, ledger, trezor, trust) come from
-- @web3icons/core (MIT-licensed, github.com/0xa3k5/web3icons). aave and lido come
-- from the same package's token set. aerodrome and kamino aren't in that package
-- (too new/small); their images come from CoinGecko's own coin listing for their
-- token (AERO, KMNO) -- the same source already trusted for every other coin image
-- in this app. Served through the existing /api/platforms/logo/{id} proxy, which
-- now short-circuits for data: URIs instead of trying to re-fetch them over HTTP.
BEGIN;

ALTER TABLE platform_cache ADD COLUMN IF NOT EXISTS kind text NOT NULL DEFAULT 'exchange';

INSERT INTO platform_cache (id, name, logo_url, kind, updated_at) VALUES
    ('metamask', 'MetaMask', 'data:image/svg+xml;base64,', 'wallet', now()),
    ('phantom', 'Phantom', 'data:image/svg+xml;base64,', 'wallet', now()),
    ('rabby', 'Rabby', 'data:image/svg+xml;base64,', 'wallet', now()),
    ('ledger', 'Ledger', 'data:image/svg+xml;base64,', 'wallet', now()),
    ('trezor', 'Trezor', 'data:image/svg+xml;base64,', 'wallet', now()),
    ('trust', 'Trust Wallet', 'data:image/svg+xml;base64,', 'wallet', now()),
    ('kamino', 'Kamino', 'data:image/png;base64,', 'defi', now()),
    ('aave', 'Aave', 'data:image/svg+xml;base64,', 'defi', now()),
    ('aerodrome', 'Aerodrome', 'data:image/png;base64,', 'defi', now()),
    ('lido', 'Lido', 'data:image/svg+xml;base64,', 'defi', now())
ON CONFLICT (id) DO UPDATE SET
    logo_url = EXCLUDED.logo_url,
    kind = EXCLUDED.kind,
    updated_at = EXCLUDED.updated_at;

COMMIT;
